"""
Parameterized generator for GH34_tokio_7910.

Source PR:    https://github.com/tokio-rs/tokio/pull/7910
Source Issue: https://github.com/tokio-rs/tokio/issues/6439

Seed varies: renames 'after' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH34_tokio_7910'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH34_tokio_7910'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('after', 'after' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH34_tokio_7910',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'tokio-rs/tokio',
                "pr_number": 7910,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/tokio-rs/tokio/pull/7910",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'tokio/src/runtime/blocking/pool.rs': '//! Thread pool for blocking operations\n\nuse crate::loom::sync::{Arc, Condvar, Mutex};\nuse crate::loom::thread;\nuse crate::runtime::blocking::schedule::BlockingSchedule;\nuse crate::runtime::blocking::{shutdown, BlockingTask};\nuse crate::runtime::builder::ThreadNameFn;\nuse crate::runtime::task::{self, JoinHandle};\nuse crate::runtime::{Builder, Callback, Handle, BOX_FUTURE_THRESHOLD};\nuse crate::util::metric_atomics::MetricAtomicUsize;\nuse crate::util::trace::{blocking_task, SpawnMeta};\n\nuse std::collections::{HashMap, VecDeque};\nuse std::fmt;\nuse std::io;\nuse std::sync::atomic::Ordering;\nuse std::time::Duration;\n\npub(crate) struct BlockingPool {\n    spawner: Spawner,\n    shutdown_rx: shutdown::Receiver,\n}\n\n#[derive(Clone)]\npub(crate) struct Spawner {\n    inner: Arc<Inner>,\n}\n\n#[derive(Default)]\npub(crate) struct SpawnerMetrics {\n    num_threads: MetricAtomicUsize,\n    num_idle_threads: MetricAtomicUsize,\n    queue_depth: MetricAtomicUsize,\n}\n\nimpl SpawnerMetrics {\n    fn num_threads(&self) -> usize {\n        self.num_threads.load(Ordering::Relaxed)\n    }\n\n    fn num_idle_threads(&self) -> usize {\n        self.num_idle_threads.load(Ordering::Relaxed)\n    }\n\n    cfg_unstable_metrics! {\n        fn queue_depth(&self) -> usize {\n            self.queue_depth.load(Ordering::Relaxed)\n        }\n    }\n\n    fn inc_num_threads(&self) {\n        self.num_threads.increment();\n    }\n\n    fn dec_num_threads(&self) {\n        self.num_threads.decrement();\n    }\n\n    fn inc_num_idle_threads(&self) {\n        self.num_idle_threads.increment();\n    }\n\n    fn dec_num_idle_threads(&self) -> usize {\n        self.num_idle_threads.decrement()\n    }\n\n    fn inc_queue_depth(&self) {\n        self.queue_depth.increment();\n    }\n\n    fn dec_queue_depth(&self) {\n        self.queue_depth.decrement();\n    }\n}\n\nstruct Inner {\n    /// State shared between worker threads.\n    shared: Mutex<Shared>,\n\n    /// Pool threads wait on this.\n    condvar: Condvar,\n\n    /// Spawned threads use this name.\n    thread_name: ThreadNameFn,\n\n    /// Spawned thread stack size.\n    stack_size: Option<usize>,\n\n    /// Call after a thread starts.\n    after_start: Option<Callback>,\n\n    /// Call before a thread stops.\n    before_stop: Option<Callback>,\n\n    // Maximum number of threads.\n    thread_cap: usize,\n\n    // Customizable wait timeout.\n    keep_alive: Duration,\n\n    // Metrics about the pool.\n    metrics: SpawnerMetrics,\n}\n\nstruct Shared {\n    queue: VecDeque<Task>,\n    num_notify: u32,\n    shutdown: bool,\n    shutdown_tx: Option<shutdown::Sender>,\n    /// Prior to shutdown, we clean up `JoinHandles` by having each timed-out\n    /// thread join on the previous timed-out thread. This is not strictly\n    /// necessary but helps avoid Valgrind false positives, see\n    /// <https://github.com/tokio-rs/tokio/commit/646fbae76535e397ef79dbcaacb945d4c829f666>\n    /// for more information.\n    last_exiting_thread: Option<thread::JoinHandle<()>>,\n    /// This holds the `JoinHandles` for all running threads; on shutdown, the thread\n    /// calling shutdown handles joining on these.\n    worker_threads: HashMap<usize, thread::JoinHandle<()>>,\n    /// This is a counter used to iterate `worker_threads` in a consistent order (for loom\'s\n    /// benefit).\n    worker_thread_index: usize,\n}\n\npub(crate) struct Task {\n    task: task::UnownedTask<BlockingSchedule>,\n    mandatory: Mandatory,\n}\n\n#[derive(PartialEq, Eq)]\npub(crate) enum Mandatory {\n    #[cfg_attr(not(feature = "fs"), allow(dead_code))]\n    Mandatory,\n    NonMandatory,\n}\n\npub(crate) enum SpawnError {\n    /// Pool is shutting down and the task was not scheduled\n    ShuttingDown,\n    /// There are no worker threads available to take the task\n    /// and the OS failed to spawn a new one\n    NoThreads(io::Error),\n}\n\nimpl From<SpawnError> for io::Error {\n    fn from(e: SpawnError) -> Self {\n        match e {\n            SpawnError::ShuttingDown => {\n                io::Error::new(io::ErrorKind::Other, "blocking pool shutting down")\n            }\n            SpawnError::NoThreads(e) => e,\n        }\n    }\n}\n\nimpl Task {\n    pub(crate) fn new(task: task::UnownedTask<BlockingSchedule>, mandatory: Mandatory) -> Task {\n        Task { task, mandatory }\n    }\n\n    fn run(self) {\n        self.task.run();\n    }\n\n    fn shutdown_or_run_if_mandatory(self) {\n        match self.mandatory {\n            Mandatory::NonMandatory => self.task.shutdown(),\n            Mandatory::Mandatory => self.task.run(),\n        }\n    }\n}\n\nconst KEEP_ALIVE: Duration = Duration::from_secs(10);\n\n/// Runs the provided function on an executor dedicated to blocking operations.\n/// Tasks will be scheduled as non-mandatory, meaning they may not get executed\n/// in case of runtime shutdown.\n#[track_caller]\n#[cfg_attr(target_os = "wasi", allow(dead_code))]\npub(crate) fn spawn_blocking<F, R>(func: F) -> JoinHandle<R>\nwhere\n    F: FnOnce() -> R + Send + \'static,\n    R: Send + \'static,\n{\n    let rt = Handle::current();\n    rt.spawn_blocking(func)\n}\n\ncfg_fs! {\n    #[cfg_attr(any(\n        all(loom, not(test)), // the function is covered by loom tests\n        test\n    ), allow(dead_code))]\n    /// Runs the provided function on an executor dedicated to blocking\n    /// operations. Tasks will be scheduled as mandatory, meaning they are\n    /// guaranteed to run unless a shutdown is already taking place. In case a\n    /// shutdown is already taking place, `None` will be returned.\n    pub(crate) fn spawn_mandatory_blocking<F, R>(func: F) -> Option<JoinHandle<R>>\n    where\n        F: FnOnce() -> R + Send + \'static,\n        R: Send + \'static,\n    {\n        let rt = Handle::current();\n        rt.inner.blocking_spawner().spawn_mandatory_blocking(&rt, func)\n    }\n}\n\n// ===== impl BlockingPool =====\n\nimpl BlockingPool {\n    pub(crate) fn new(builder: &Builder, thread_cap: usize) -> BlockingPool {\n        let (shutdown_tx, shutdown_rx) = shutdown::channel();\n        let keep_alive = builder.keep_alive.unwrap_or(KEEP_ALIVE);\n\n        BlockingPool {\n            spawner: Spawner {\n                inner: Arc::new(Inner {\n                    shared: Mutex::new(Shared {\n                        queue: VecDeque::new(),\n                        num_notify: 0,\n                        shutdown: false,\n                        shutdown_tx: Some(shutdown_tx),\n                        last_exiting_thread: None,\n                        worker_threads: HashMap::new(),\n                        worker_thread_index: 0,\n                    }),\n                    condvar: Condvar::new(),\n                    thread_name: builder.thread_name.clone(),\n                    stack_size: builder.thread_stack_size,\n                    after_start: builder.after_start.clone(),\n                    before_stop: builder.before_stop.clone(),\n                    thread_cap,\n                    keep_alive,\n                    metrics: SpawnerMetrics::default(),\n                }),\n            },\n            shutdown_rx,\n        }\n    }\n\n    pub(crate) fn spawner(&self) -> &Spawner {\n        &self.spawner\n    }\n\n    pub(crate) fn shutdown(&mut self, timeout: Option<Duration>) {\n        let mut shared = self.spawner.inner.shared.lock();\n\n        // The function can be called multiple times. First, by explicitly\n        // calling `shutdown` then by the drop handler calling `shutdown`. This\n        // prevents shutting down twice.\n        if shared.shutdown {\n            return;\n        }\n\n        shared.shutdown = true;\n        shared.shutdown_tx = None;\n        self.spawner.inner.condvar.notify_all();\n\n        let last_exited_thread = std::mem::take(&mut shared.last_exiting_thread);\n        let workers = std::mem::take(&mut shared.worker_threads);\n\n        drop(shared);\n\n        if self.shutdown_rx.wait(timeout) {\n            let _ = last_exited_thread.map(thread::JoinHandle::join);\n\n            // Loom requires that execution be deterministic, so sort by thread ID before joining.\n            // (HashMaps use a randomly-seeded hash function, so the order is nondeterministic)\n            #[cfg(loom)]\n            let workers: Vec<(usize, thread::JoinHandle<()>)> = {\n                let mut workers: Vec<_> = workers.into_iter().collect();\n                workers.sort_by_key(|(id, _)| *id);\n                workers\n            };\n\n            for (_id, handle) in workers {\n                let _ = handle.join();\n            }\n        }\n    }\n}\n\nimpl Drop for BlockingPool {\n    fn drop(&mut self) {\n        self.shutdown(None);\n    }\n}\n\nimpl fmt::Debug for BlockingPool {\n    fn fmt(&self, fmt: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        fmt.debug_struct("BlockingPool").finish()\n    }\n}\n\n// ===== impl Spawner =====\n\nimpl Spawner {\n    #[track_caller]\n    pub(crate) fn spawn_blocking<F, R>(&self, rt: &Handle, func: F) -> JoinHandle<R>\n    where\n        F: FnOnce() -> R + Send + \'static,\n        R: Send + \'static,\n    {\n        let fn_size = std::mem::size_of::<F>();\n        let (join_handle, spawn_result) = if fn_size > BOX_FUTURE_THRESHOLD {\n            self.spawn_blocking_inner(\n                Box::new(func),\n                Mandatory::NonMandatory,\n                SpawnMeta::new_unnamed(fn_size),\n                rt,\n            )\n        } else {\n            self.spawn_blocking_inner(\n                func,\n                Mandatory::NonMandatory,\n                SpawnMeta::new_unnamed(fn_size),\n                rt,\n            )\n        };\n\n        match spawn_result {\n            Ok(()) => join_handle,\n            // Compat: do not panic here, return the join_handle even though it will never resolve\n            Err(SpawnError::ShuttingDown) => join_handle,\n            Err(SpawnError::NoThreads(e)) => {\n                panic!("OS can\'t spawn worker thread: {e}")\n            }\n        }\n    }\n\n    cfg_fs! {\n        #[track_caller]\n        #[cfg_attr(any(\n            all(loom, not(test)), // the function is covered by loom tests\n            test\n        ), allow(dead_code))]\n        pub(crate) fn spawn_mandatory_blocking<F, R>(&self, rt: &Handle, func: F) -> Option<JoinHandle<R>>\n        where\n            F: FnOnce() -> R + Send + \'static,\n            R: Send + \'static,\n        {\n            let fn_size = std::mem::size_of::<F>();\n            let (join_handle, spawn_result) = if fn_size > BOX_FUTURE_THRESHOLD {\n                self.spawn_blocking_inner(\n                    Box::new(func),\n                    Mandatory::Mandatory,\n                    SpawnMeta::new_unnamed(fn_size),\n                    rt,\n                )\n            } else {\n                self.spawn_blocking_inner(\n                    func,\n                    Mandatory::Mandatory,\n                    SpawnMeta::new_unnamed(fn_size),\n                    rt,\n                )\n            };\n\n            if spawn_result.is_ok() {\n                Some(join_handle)\n            } else {\n                None\n            }\n        }\n    }\n\n    #[track_caller]\n    pub(crate) fn spawn_blocking_inner<F, R>(\n        &self,\n        func: F,\n        is_mandatory: Mandatory,\n        spawn_meta: SpawnMeta<\'_>,\n        rt: &Handle,\n    ) -> (JoinHandle<R>, Result<(), SpawnError>)\n    where\n        F: FnOnce() -> R + Send + \'static,\n        R: Send + \'static,\n    {\n        let id = task::Id::next();\n        let fut =\n            blocking_task::<F, BlockingTask<F>>(BlockingTask::new(func), spawn_meta, id.as_u64());\n\n        let (task, handle) = task::unowned(\n            fut,\n            BlockingSchedule::new(rt),\n            id,\n            task::SpawnLocation::capture(),\n        );\n\n        let spawned = self.spawn_task(Task::new(task, is_mandatory), rt);\n        (handle, spawned)\n    }\n\n    fn spawn_task(&self, task: Task, rt: &Handle) -> Result<(), SpawnError> {\n        let mut shared = self.inner.shared.lock();\n\n        if shared.shutdown {\n            // Shutdown the task: it\'s fine to shutdown this task (even if\n            // mandatory) because it was scheduled after the shutdown of the\n            // runtime began.\n            task.task.shutdown();\n\n            // no need to even push this task; it would never get picked up\n            return Err(SpawnError::ShuttingDown);\n        }\n\n        shared.queue.push_back(task);\n        self.inner.metrics.inc_queue_depth();\n\n        if self.inner.metrics.num_idle_threads() == 0 {\n            // No threads are able to process the task.\n\n            if self.inner.metrics.num_threads() == self.inner.thread_cap {\n                // At max number of threads\n            } else {\n                assert!(shared.shutdown_tx.is_some());\n                let shutdown_tx = shared.shutdown_tx.clone();\n\n                if let Some(shutdown_tx) = shutdown_tx {\n                    let id = shared.worker_thread_index;\n\n                    match self.spawn_thread(shutdown_tx, rt, id) {\n                        Ok(handle) => {\n                            self.inner.metrics.inc_num_threads();\n                            shared.worker_thread_index += 1;\n                            shared.worker_threads.insert(id, handle);\n                        }\n                        Err(ref e)\n                            if is_temporary_os_thread_error(e)\n                                && self.inner.metrics.num_threads() > 0 =>\n                        {\n                            // OS temporarily failed to spawn a new thread.\n                            // The task will be picked up eventually by a currently\n                            // busy thread.\n                        }\n                        Err(e) => {\n                            // The OS refused to spawn the thread and there is no thread\n                            // to pick up the task that has just been pushed to the queue.\n                            return Err(SpawnError::NoThreads(e));\n                        }\n                    }\n                }\n            }\n        } else {\n            // Notify an idle worker thread. The notification counter\n            // is used to count the needed amount of notifications\n            // exactly. Thread libraries may generate spurious\n            // wakeups, this counter is used to keep us in a\n            // consistent state.\n            self.inner.metrics.dec_num_idle_threads();\n            shared.num_notify += 1;\n            self.inner.condvar.notify_one();\n        }\n\n        Ok(())\n    }\n\n    fn spawn_thread(\n        &self,\n        shutdown_tx: shutdown::Sender,\n        rt: &Handle,\n        id: usize,\n    ) -> io::Result<thread::JoinHandle<()>> {\n        let mut builder = thread::Builder::new().name((self.inner.thread_name)());\n\n        if let Some(stack_size) = self.inner.stack_size {\n            builder = builder.stack_size(stack_size);\n        }\n\n        let rt = rt.clone();\n\n        builder.spawn(move || {\n            // Only the reference should be moved into the closure\n            let _enter = rt.enter();\n            rt.inner.blocking_spawner().inner.run(id);\n            drop(shutdown_tx);\n        })\n    }\n}\n\ncfg_unstable_metrics! {\n    impl Spawner {\n        pub(crate) fn num_threads(&self) -> usize {\n            self.inner.metrics.num_threads()\n        }\n\n        pub(crate) fn num_idle_threads(&self) -> usize {\n            self.inner.metrics.num_idle_threads()\n        }\n\n        pub(crate) fn queue_depth(&self) -> usize {\n            self.inner.metrics.queue_depth()\n        }\n    }\n}\n\n// Tells whether the error when spawning a thread is temporary.\n#[inline]\nfn is_temporary_os_thread_error(error: &io::Error) -> bool {\n    matches!(error.kind(), io::ErrorKind::WouldBlock)\n}\n\nimpl Inner {\n    fn run(&self, worker_thread_id: usize) {\n        if let Some(f) = &self.after_start {\n            f();\n        }\n\n        let mut shared = self.shared.lock();\n        let mut join_on_thread = None;\n\n        \'main: loop {\n            // BUSY\n            while let Some(task) = shared.queue.pop_front() {\n                self.metrics.dec_queue_depth();\n                drop(shared);\n                task.run();\n\n                shared = self.shared.lock();\n            }\n\n            // IDLE\n            self.metrics.inc_num_idle_threads();\n\n            while !shared.shutdown {\n                let lock_result = self.condvar.wait_timeout(shared, self.keep_alive).unwrap();\n\n                shared = lock_result.0;\n                let timeout_result = lock_result.1;\n\n                if shared.num_notify != 0 {\n                    // We have received a legitimate wakeup,\n                    // acknowledge it by decrementing the counter\n                    // and transition to the BUSY state.\n                    shared.num_notify -= 1;\n                    break;\n                }\n\n                // Even if the condvar "timed out", if the pool is entering the\n                // shutdown phase, we want to perform the cleanup logic.\n                if !shared.shutdown && timeout_result.timed_out() {\n                    // We\'ll join the prior timed-out thread\'s JoinHandle after dropping the lock.\n                    // This isn\'t done when shutting down, because the thread calling shutdown will\n                    // handle joining everything.\n                    let my_handle = shared.worker_threads.remove(&worker_thread_id);\n                    join_on_thread = std::mem::replace(&mut shared.last_exiting_thread, my_handle);\n\n                    break \'main;\n                }\n\n                // Spurious wakeup detected, go back to sleep.\n            }\n\n            if shared.shutdown {\n                // Drain the queue\n                while let Some(task) = shared.queue.pop_front() {\n                    self.metrics.dec_queue_depth();\n                    drop(shared);\n\n                    task.shutdown_or_run_if_mandatory();\n\n                    shared = self.shared.lock();\n                }\n\n                // Work was produced, and we "took" it (by decrementing num_notify).\n                // This means that num_idle was decremented once for our wakeup.\n                // But, since we are exiting, we need to "undo" that, as we\'ll stay idle.\n                self.metrics.inc_num_idle_threads();\n                // NOTE: Technically we should also do num_notify++ and notify again,\n                // but since we\'re shutting down anyway, that won\'t be necessary.\n                break;\n            }\n        }\n\n        // Thread exit\n        self.metrics.dec_num_threads();\n\n        // num_idle should now be tracked exactly, panic\n        // with a descriptive message if it is not the\n        // case.\n        let prev_idle = self.metrics.dec_num_idle_threads();\n        assert!(\n            prev_idle >= self.metrics.num_idle_threads(),\n            "num_idle_threads underflowed on thread exit"\n        );\n\n        if shared.shutdown && self.metrics.num_threads() == 0 {\n            self.condvar.notify_one();\n        }\n\n        drop(shared);\n\n        if let Some(f) = &self.before_stop {\n            f();\n        }\n\n        if let Some(handle) = join_on_thread {\n            let _ = handle.join();\n        }\n    }\n}\n\nimpl fmt::Debug for Spawner {\n    fn fmt(&self, fmt: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        fmt.debug_struct("blocking::Spawner").finish()\n    }\n}\n',
            'tokio/tests/rt_unstable_metrics.rs': '#![warn(rust_2018_idioms)]\n#![cfg(all(\n    feature = "full",\n    tokio_unstable,\n    not(target_os = "wasi"),\n    target_has_atomic = "64"\n))]\n\nuse std::future::Future;\nuse std::sync::{mpsc, Arc, Mutex};\nuse std::task::Poll;\nuse std::thread;\nuse tokio::macros::support::poll_fn;\n\nuse tokio::runtime::{HistogramConfiguration, HistogramScale, LogHistogram, Runtime};\nuse tokio::task::consume_budget;\nuse tokio::time::{self, Duration};\n\n#[test]\nfn num_workers() {\n    let rt = current_thread();\n    assert_eq!(1, rt.metrics().num_workers());\n\n    let rt = threaded();\n    assert_eq!(2, rt.metrics().num_workers());\n}\n\n#[test]\nfn num_blocking_threads() {\n    let rt = current_thread();\n    assert_eq!(0, rt.metrics().num_blocking_threads());\n    let _ = rt.block_on(rt.spawn_blocking(move || {}));\n    assert_eq!(1, rt.metrics().num_blocking_threads());\n\n    let rt = threaded();\n    assert_eq!(0, rt.metrics().num_blocking_threads());\n    let _ = rt.block_on(rt.spawn_blocking(move || {}));\n    assert_eq!(1, rt.metrics().num_blocking_threads());\n}\n\n#[test]\nfn num_idle_blocking_threads() {\n    let rt = current_thread();\n    assert_eq!(0, rt.metrics().num_idle_blocking_threads());\n    let _ = rt.block_on(rt.spawn_blocking(move || {}));\n    rt.block_on(async {\n        time::sleep(Duration::from_millis(5)).await;\n    });\n\n    // We need to wait until the blocking thread has become idle. Usually 5ms is\n    // enough for this to happen, but not always. When it isn\'t enough, sleep\n    // for another second. We don\'t always wait for a whole second since we want\n    // the test suite to finish quickly.\n    //\n    // Note that the timeout for idle threads to be killed is 10 seconds.\n    if 0 == rt.metrics().num_idle_blocking_threads() {\n        rt.block_on(async {\n            time::sleep(Duration::from_secs(1)).await;\n        });\n    }\n\n    assert_eq!(1, rt.metrics().num_idle_blocking_threads());\n}\n\n#[test]\nfn blocking_queue_depth() {\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .max_blocking_threads(1)\n        .build()\n        .unwrap();\n\n    assert_eq!(0, rt.metrics().blocking_queue_depth());\n\n    let ready = Arc::new(Mutex::new(()));\n    let guard = ready.lock().unwrap();\n\n    let ready_cloned = ready.clone();\n    let wait_until_ready = move || {\n        let _unused = ready_cloned.lock().unwrap();\n    };\n\n    let h1 = rt.spawn_blocking(wait_until_ready.clone());\n    let h2 = rt.spawn_blocking(wait_until_ready);\n    assert!(rt.metrics().blocking_queue_depth() > 0);\n\n    drop(guard);\n\n    let _ = rt.block_on(h1);\n    let _ = rt.block_on(h2);\n\n    assert_eq!(0, rt.metrics().blocking_queue_depth());\n}\n\n#[test]\nfn spawned_tasks_count() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n    assert_eq!(0, metrics.spawned_tasks_count());\n\n    rt.block_on(rt.spawn(async move {\n        assert_eq!(1, metrics.spawned_tasks_count());\n    }))\n    .unwrap();\n\n    assert_eq!(1, rt.metrics().spawned_tasks_count());\n\n    let rt = threaded();\n    let metrics = rt.metrics();\n    assert_eq!(0, metrics.spawned_tasks_count());\n\n    rt.block_on(rt.spawn(async move {\n        assert_eq!(1, metrics.spawned_tasks_count());\n    }))\n    .unwrap();\n\n    assert_eq!(1, rt.metrics().spawned_tasks_count());\n}\n\n#[test]\nfn remote_schedule_count() {\n    use std::thread;\n\n    let rt = current_thread();\n    let handle = rt.handle().clone();\n    let task = thread::spawn(move || {\n        handle.spawn(async {\n            // DO nothing\n        })\n    })\n    .join()\n    .unwrap();\n\n    rt.block_on(task).unwrap();\n\n    assert_eq!(1, rt.metrics().remote_schedule_count());\n\n    let rt = threaded();\n    let handle = rt.handle().clone();\n    let task = thread::spawn(move || {\n        handle.spawn(async {\n            // DO nothing\n        })\n    })\n    .join()\n    .unwrap();\n\n    rt.block_on(task).unwrap();\n\n    assert_eq!(1, rt.metrics().remote_schedule_count());\n}\n\n#[test]\nfn worker_thread_id_current_thread() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n\n    // Check that runtime is on this thread.\n    rt.block_on(async {});\n    assert_eq!(Some(thread::current().id()), metrics.worker_thread_id(0));\n\n    // Move runtime to another thread.\n    let thread_id = std::thread::scope(|scope| {\n        let join_handle = scope.spawn(|| {\n            rt.block_on(async {});\n        });\n        join_handle.thread().id()\n    });\n    assert_eq!(Some(thread_id), metrics.worker_thread_id(0));\n\n    // Move runtime back to this thread.\n    rt.block_on(async {});\n    assert_eq!(Some(thread::current().id()), metrics.worker_thread_id(0));\n}\n\n#[test]\nfn worker_thread_id_threaded() {\n    let rt = threaded();\n    let metrics = rt.metrics();\n\n    rt.block_on(rt.spawn(async move {\n        // Check that we are running on a worker thread and determine\n        // the index of our worker.\n        let thread_id = std::thread::current().id();\n        let this_worker = (0..2)\n            .position(|w| metrics.worker_thread_id(w) == Some(thread_id))\n            .expect("task not running on any worker thread");\n\n        // Force worker to another thread.\n        let moved_thread_id = tokio::task::block_in_place(|| {\n            assert_eq!(thread_id, std::thread::current().id());\n\n            // Wait for worker to move to another thread.\n            for _ in 0..100 {\n                let new_id = metrics.worker_thread_id(this_worker).unwrap();\n                if thread_id != new_id {\n                    return new_id;\n                }\n                std::thread::sleep(Duration::from_millis(100));\n            }\n\n            panic!("worker did not move to new thread");\n        });\n\n        // After blocking task worker either stays on new thread or\n        // is moved back to current thread.\n        assert!(\n            metrics.worker_thread_id(this_worker) == Some(moved_thread_id)\n                || metrics.worker_thread_id(this_worker) == Some(thread_id)\n        );\n    }))\n    .unwrap()\n}\n\n#[test]\nfn worker_noop_count() {\n    // There isn\'t really a great way to generate no-op parks as they happen as\n    // false-positive events under concurrency.\n\n    let rt = current_thread();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        time::sleep(Duration::from_millis(1)).await;\n    });\n    drop(rt);\n    assert!(0 < metrics.worker_noop_count(0));\n\n    let rt = threaded();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        time::sleep(Duration::from_millis(1)).await;\n    });\n    drop(rt);\n    assert!(0 < metrics.worker_noop_count(0));\n    assert!(0 < metrics.worker_noop_count(1));\n}\n\n#[test]\nfn worker_steal_count() {\n    // This metric only applies to the multi-threaded runtime.\n    for _ in 0..10 {\n        let rt = threaded_no_lifo();\n        let metrics = rt.metrics();\n\n        let successfully_spawned_stealable_task = rt.block_on(async {\n            // The call to `try_spawn_stealable_task` may time out, which means\n            // that the sending task couldn\'t be scheduled due to a deadlock in\n            // the runtime.\n            // This is expected behaviour, we just retry until we succeed or\n            // exhaust all tries, the latter causing this test to fail.\n            try_spawn_stealable_task().await.is_ok()\n        });\n\n        drop(rt);\n\n        if successfully_spawned_stealable_task {\n            let n: u64 = (0..metrics.num_workers())\n                .map(|i| metrics.worker_steal_count(i))\n                .sum();\n\n            assert_eq!(1, n);\n            return;\n        }\n    }\n\n    panic!("exhausted every try to schedule the stealable task");\n}\n\n#[test]\nfn worker_poll_count_and_time() {\n    const N: u64 = 5;\n\n    async fn task() {\n        // Sync sleep\n        std::thread::sleep(std::time::Duration::from_micros(10));\n    }\n\n    let rt = current_thread();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        for _ in 0..N {\n            tokio::spawn(task()).await.unwrap();\n        }\n    });\n    drop(rt);\n    assert_eq!(N, metrics.worker_poll_count(0));\n    // Not currently supported for current-thread runtime\n    assert_eq!(Duration::default(), metrics.worker_mean_poll_time(0));\n\n    // Does not populate the histogram\n    assert!(!metrics.poll_time_histogram_enabled());\n    for i in 0..10 {\n        assert_eq!(0, metrics.poll_time_histogram_bucket_count(0, i));\n    }\n\n    let rt = threaded();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        for _ in 0..N {\n            tokio::spawn(task()).await.unwrap();\n        }\n    });\n    drop(rt);\n    // Account for the `block_on` task\n    let n = (0..metrics.num_workers())\n        .map(|i| metrics.worker_poll_count(i))\n        .sum();\n\n    assert_eq!(N, n);\n\n    let n: Duration = (0..metrics.num_workers())\n        .map(|i| metrics.worker_mean_poll_time(i))\n        .sum();\n\n    assert!(n > Duration::default());\n\n    // Does not populate the histogram\n    assert!(!metrics.poll_time_histogram_enabled());\n    for n in 0..metrics.num_workers() {\n        for i in 0..10 {\n            assert_eq!(0, metrics.poll_time_histogram_bucket_count(n, i));\n        }\n    }\n}\n\n#[test]\nfn log_histogram() {\n    const N: u64 = 50;\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_time_histogram_configuration(HistogramConfiguration::log(\n            LogHistogram::builder()\n                .max_value(Duration::from_secs(60))\n                .min_value(Duration::from_nanos(100))\n                .max_error(0.25),\n        ))\n        .build()\n        .unwrap();\n    let metrics = rt.metrics();\n    let num_buckets = rt.metrics().poll_time_histogram_num_buckets();\n    assert_eq!(num_buckets, 119);\n    rt.block_on(async {\n        for _ in 0..N {\n            tokio::spawn(async {}).await.unwrap();\n        }\n    });\n    drop(rt);\n    assert_eq!(\n        metrics.poll_time_histogram_bucket_range(0),\n        Duration::from_nanos(0)..Duration::from_nanos(96)\n    );\n    assert_eq!(\n        metrics.poll_time_histogram_bucket_range(1),\n        Duration::from_nanos(96)..Duration::from_nanos(96 + 2_u64.pow(4))\n    );\n    assert_eq!(\n        metrics.poll_time_histogram_bucket_range(118).end,\n        Duration::from_nanos(u64::MAX)\n    );\n    let n = (0..metrics.num_workers())\n        .flat_map(|i| (0..num_buckets).map(move |j| (i, j)))\n        .map(|(worker, bucket)| metrics.poll_time_histogram_bucket_count(worker, bucket))\n        .sum();\n    assert_eq!(N, n);\n}\n\n#[test]\nfn minimal_log_histogram() {\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_time_histogram_configuration(HistogramConfiguration::log(\n            LogHistogram::builder()\n                .max_value(Duration::from_millis(4))\n                .min_value(Duration::from_micros(20))\n                .precision_exact(0),\n        ))\n        .build()\n        .unwrap();\n    let metrics = rt.metrics();\n    let num_buckets = rt.metrics().poll_time_histogram_num_buckets();\n    for b in 1..num_buckets - 1 {\n        let range = metrics.poll_time_histogram_bucket_range(b);\n        let size = range.end - range.start;\n        // Assert the buckets continue doubling in size\n        assert_eq!(\n            size,\n            Duration::from_nanos((1 << (b - 1)) * 16384),\n            "incorrect range for {b}"\n        );\n    }\n    assert_eq!(num_buckets, 10);\n}\n\n#[test]\n#[allow(deprecated)]\nfn legacy_log_histogram() {\n    let rt = tokio::runtime::Builder::new_multi_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_count_histogram_scale(HistogramScale::Log)\n        .metrics_poll_count_histogram_resolution(Duration::from_micros(50))\n        .metrics_poll_count_histogram_buckets(20)\n        .build()\n        .unwrap();\n    let num_buckets = rt.metrics().poll_time_histogram_num_buckets();\n    assert_eq!(num_buckets, 20);\n}\n\n#[test]\nfn log_histogram_default_configuration() {\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_time_histogram_configuration(HistogramConfiguration::log(\n            LogHistogram::default(),\n        ))\n        .build()\n        .unwrap();\n    let num_buckets = rt.metrics().poll_time_histogram_num_buckets();\n    assert_eq!(num_buckets, 119);\n}\n\n#[test]\nfn worker_poll_count_histogram() {\n    const N: u64 = 5;\n\n    let rts = [\n        tokio::runtime::Builder::new_current_thread()\n            .enable_all()\n            .enable_metrics_poll_time_histogram()\n            .metrics_poll_time_histogram_configuration(HistogramConfiguration::linear(\n                Duration::from_millis(50),\n                3,\n            ))\n            .build()\n            .unwrap(),\n        tokio::runtime::Builder::new_multi_thread()\n            .worker_threads(2)\n            .enable_all()\n            .enable_metrics_poll_time_histogram()\n            .metrics_poll_time_histogram_configuration(HistogramConfiguration::linear(\n                Duration::from_millis(50),\n                3,\n            ))\n            .build()\n            .unwrap(),\n    ];\n\n    for rt in rts {\n        let metrics = rt.metrics();\n        rt.block_on(async {\n            for _ in 0..N {\n                tokio::spawn(async {}).await.unwrap();\n            }\n        });\n        drop(rt);\n\n        let num_workers = metrics.num_workers();\n        let num_buckets = metrics.poll_time_histogram_num_buckets();\n\n        assert!(metrics.poll_time_histogram_enabled());\n        assert_eq!(num_buckets, 3);\n\n        let n = (0..num_workers)\n            .flat_map(|i| (0..num_buckets).map(move |j| (i, j)))\n            .map(|(worker, bucket)| metrics.poll_time_histogram_bucket_count(worker, bucket))\n            .sum();\n        assert_eq!(N, n);\n    }\n}\n\n#[test]\nfn worker_poll_count_histogram_range() {\n    let max = Duration::from_nanos(u64::MAX);\n\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_time_histogram_configuration(HistogramConfiguration::linear(us(50), 3))\n        .build()\n        .unwrap();\n    let metrics = rt.metrics();\n\n    assert_eq!(metrics.poll_time_histogram_bucket_range(0), us(0)..us(50));\n    assert_eq!(metrics.poll_time_histogram_bucket_range(1), us(50)..us(100));\n    assert_eq!(metrics.poll_time_histogram_bucket_range(2), us(100)..max);\n\n    // ensure the old methods work too\n    #[allow(deprecated)]\n    let rt = tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .enable_metrics_poll_time_histogram()\n        .metrics_poll_count_histogram_scale(tokio::runtime::HistogramScale::Log)\n        .metrics_poll_count_histogram_buckets(3)\n        .metrics_poll_count_histogram_resolution(us(50))\n        .build()\n        .unwrap();\n    let metrics = rt.metrics();\n\n    let a = Duration::from_nanos(50000_u64.next_power_of_two());\n    let b = a * 2;\n\n    assert_eq!(metrics.poll_time_histogram_bucket_range(0), us(0)..a);\n    assert_eq!(metrics.poll_time_histogram_bucket_range(1), a..b);\n    assert_eq!(metrics.poll_time_histogram_bucket_range(2), b..max);\n}\n\n#[test]\nfn worker_poll_count_histogram_disabled_without_explicit_enable() {\n    let rts = [\n        tokio::runtime::Builder::new_current_thread()\n            .enable_all()\n            .metrics_poll_time_histogram_configuration(HistogramConfiguration::linear(\n                Duration::from_millis(50),\n                3,\n            ))\n            .build()\n            .unwrap(),\n        tokio::runtime::Builder::new_multi_thread()\n            .worker_threads(2)\n            .enable_all()\n            .metrics_poll_time_histogram_configuration(HistogramConfiguration::linear(\n                Duration::from_millis(50),\n                3,\n            ))\n            .build()\n            .unwrap(),\n    ];\n\n    for rt in rts {\n        let metrics = rt.metrics();\n        assert!(!metrics.poll_time_histogram_enabled());\n    }\n}\n\n#[test]\nfn worker_local_schedule_count() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        tokio::spawn(async {}).await.unwrap();\n    });\n    drop(rt);\n\n    assert_eq!(1, metrics.worker_local_schedule_count(0));\n    assert_eq!(0, metrics.remote_schedule_count());\n\n    let rt = threaded();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        // Move to the runtime\n        tokio::spawn(async {\n            tokio::spawn(async {}).await.unwrap();\n        })\n        .await\n        .unwrap();\n    });\n    drop(rt);\n\n    let n: u64 = (0..metrics.num_workers())\n        .map(|i| metrics.worker_local_schedule_count(i))\n        .sum();\n\n    assert_eq!(2, n);\n    assert_eq!(1, metrics.remote_schedule_count());\n}\n\n#[test]\nfn worker_overflow_count() {\n    // Only applies to the threaded worker\n    let rt = threaded();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        // Move to the runtime\n        tokio::spawn(async {\n            let (tx1, rx1) = std::sync::mpsc::channel();\n            let (tx2, rx2) = std::sync::mpsc::channel();\n\n            // First, we need to block the other worker until all tasks have\n            // been spawned.\n            //\n            // We spawn from outside the runtime to ensure that the other worker\n            // will pick it up:\n            // <https://github.com/tokio-rs/tokio/issues/4730>\n            tokio::task::spawn_blocking(|| {\n                tokio::spawn(async move {\n                    tx1.send(()).unwrap();\n                    rx2.recv().unwrap();\n                });\n            });\n\n            rx1.recv().unwrap();\n\n            // Spawn many tasks\n            for _ in 0..300 {\n                tokio::spawn(async {});\n            }\n\n            tx2.send(()).unwrap();\n        })\n        .await\n        .unwrap();\n    });\n    drop(rt);\n\n    let n: u64 = (0..metrics.num_workers())\n        .map(|i| metrics.worker_overflow_count(i))\n        .sum();\n\n    assert_eq!(1, n);\n}\n\n#[test]\nfn worker_local_queue_depth() {\n    const N: usize = 100;\n\n    let rt = current_thread();\n    let metrics = rt.metrics();\n    rt.block_on(async {\n        for _ in 0..N {\n            tokio::spawn(async {});\n        }\n\n        assert_eq!(N, metrics.worker_local_queue_depth(0));\n    });\n\n    let rt = threaded();\n    let metrics = rt.metrics();\n    rt.block_on(async move {\n        // Move to the runtime\n        tokio::spawn(async move {\n            let (tx1, rx1) = std::sync::mpsc::channel();\n            let (tx2, rx2) = std::sync::mpsc::channel();\n\n            // First, we need to block the other worker until all tasks have\n            // been spawned.\n            tokio::spawn(async move {\n                tx1.send(()).unwrap();\n                rx2.recv().unwrap();\n            });\n\n            // Bump the next-run spawn\n            tokio::spawn(async {});\n\n            rx1.recv().unwrap();\n\n            // Spawn some tasks\n            for _ in 0..100 {\n                tokio::spawn(async {});\n            }\n\n            let n: usize = (0..metrics.num_workers())\n                .map(|i| metrics.worker_local_queue_depth(i))\n                .sum();\n\n            assert_eq!(n, N);\n\n            tx2.send(()).unwrap();\n        })\n        .await\n        .unwrap();\n    });\n}\n\n#[test]\nfn budget_exhaustion_yield() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n\n    assert_eq!(0, metrics.budget_forced_yield_count());\n\n    let mut did_yield = false;\n\n    // block on a task which consumes budget until it yields\n    rt.block_on(poll_fn(|cx| loop {\n        if did_yield {\n            return Poll::Ready(());\n        }\n\n        let fut = consume_budget();\n        tokio::pin!(fut);\n\n        if fut.poll(cx).is_pending() {\n            did_yield = true;\n            return Poll::Pending;\n        }\n    }));\n\n    assert_eq!(1, rt.metrics().budget_forced_yield_count());\n}\n\n#[test]\nfn budget_exhaustion_yield_with_joins() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n\n    assert_eq!(0, metrics.budget_forced_yield_count());\n\n    let mut did_yield_1 = false;\n    let mut did_yield_2 = false;\n\n    // block on a task which consumes budget until it yields\n    rt.block_on(async {\n        tokio::join!(\n            poll_fn(|cx| loop {\n                if did_yield_1 {\n                    return Poll::Ready(());\n                }\n\n                let fut = consume_budget();\n                tokio::pin!(fut);\n\n                if fut.poll(cx).is_pending() {\n                    did_yield_1 = true;\n                    return Poll::Pending;\n                }\n            }),\n            poll_fn(|cx| loop {\n                if did_yield_2 {\n                    return Poll::Ready(());\n                }\n\n                let fut = consume_budget();\n                tokio::pin!(fut);\n\n                if fut.poll(cx).is_pending() {\n                    did_yield_2 = true;\n                    return Poll::Pending;\n                }\n            })\n        )\n    });\n\n    assert_eq!(1, rt.metrics().budget_forced_yield_count());\n}\n\n#[cfg(any(target_os = "linux", target_os = "macos"))]\n#[test]\nfn io_driver_fd_count() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n\n    assert_eq!(metrics.io_driver_fd_registered_count(), 0);\n\n    let stream = tokio::net::TcpStream::connect("google.com:80");\n    let stream = rt.block_on(async move { stream.await.unwrap() });\n\n    assert_eq!(metrics.io_driver_fd_registered_count(), 1);\n    assert_eq!(metrics.io_driver_fd_deregistered_count(), 0);\n\n    drop(stream);\n\n    assert_eq!(metrics.io_driver_fd_deregistered_count(), 1);\n    assert_eq!(metrics.io_driver_fd_registered_count(), 1);\n}\n\n#[cfg(any(target_os = "linux", target_os = "macos"))]\n#[test]\nfn io_driver_ready_count() {\n    let rt = current_thread();\n    let metrics = rt.metrics();\n\n    let stream = tokio::net::TcpStream::connect("google.com:80");\n    let _stream = rt.block_on(async move { stream.await.unwrap() });\n\n    assert_eq!(metrics.io_driver_ready_count(), 1);\n}\n\nasync fn try_spawn_stealable_task() -> Result<(), mpsc::RecvTimeoutError> {\n    // We use a blocking channel to synchronize the tasks.\n    let (tx, rx) = mpsc::channel();\n\n    // Make sure we are in the context of the runtime.\n    tokio::spawn(async move {\n        // Spawn the task that sends to the channel.\n        //\n        // Note that the runtime needs to have the lifo slot disabled to make\n        // this task stealable.\n        tokio::spawn(async move {\n            tx.send(()).unwrap();\n        });\n\n        // Blocking receive on the channel, timing out if the sending task\n        // wasn\'t scheduled in time.\n        rx.recv_timeout(Duration::from_secs(1))\n    })\n    .await\n    .unwrap()?;\n\n    Ok(())\n}\n\nfn current_thread() -> Runtime {\n    tokio::runtime::Builder::new_current_thread()\n        .enable_all()\n        .build()\n        .unwrap()\n}\n\nfn threaded() -> Runtime {\n    tokio::runtime::Builder::new_multi_thread()\n        .worker_threads(2)\n        .enable_all()\n        .build()\n        .unwrap()\n}\n\nfn threaded_no_lifo() -> Runtime {\n    tokio::runtime::Builder::new_multi_thread()\n        .worker_threads(2)\n        .disable_lifo_slot()\n        .enable_all()\n        .build()\n        .unwrap()\n}\n\nfn us(n: u64) -> Duration {\n    Duration::from_micros(n)\n}\n',
        }
